[data-theme="dark"] .tag { background: #333; color: #ccc; }
[data-theme="dark"] .timeline-content { background: #2a2a2a; box-shadow: 0 2px 8px rgba(0,0,0,0.2); }
[data-theme="dark"] .timeline-meta { border-color: #333; }
</style>

